import React from 'react';
import { Link } from 'react-router-dom';

const ProfileComponent = ({ userId, tabs, activeTab, onTabChange }) => {
  return (
    <div>
      <h1>프로필</h1>
      <div>
        {tabs.map(tab => (
          <button key={tab.key} onClick={() => onTabChange(tab.key)}>
            {tab.label}
          </button>
        ))}
      </div>
      {activeTab === 'posts'    && <div>작성한 게시글</div>}
      {activeTab === 'comments' && <div>댓글 목록</div>}
      {activeTab === 'likes'    && <div>좋아요한 글</div>}
      <Link to="/eum/community">← 커뮤니티 홈</Link>
    </div>
  );
};

export default ProfileComponent;
