import React, { useState } from 'react';
import { Outlet } from 'react-router-dom';
import ChatFloatingBar from './chat/floating/ChatFloatingBar';
import ChatPopupContainer from './chat/popup/ChatPopupContainer';

const CommunityLayout = () => {
  const [isPopupOpen, setIsPopupOpen] = useState(false);

  return (
    <div>
      <Outlet />
      {isPopupOpen && <ChatPopupContainer onClose={() => setIsPopupOpen(false)} />}
      <ChatFloatingBar onOpen={() => setIsPopupOpen(true)} />
    </div>
  );
};

export default CommunityLayout;
