import React, { useState } from 'react';
import LearnMainComponent from './LearnMainComponent';

const LearnMainContainer = () => {
  const [isAttendanceOpen, setIsAttendanceOpen] = useState(false);

  return (
    <LearnMainComponent
      isAttendanceOpen={isAttendanceOpen}
      onOpenAttendance={() => setIsAttendanceOpen(true)}
      onCloseAttendance={() => setIsAttendanceOpen(false)}
    />
  );
};

export default LearnMainContainer;
