import React from 'react';
import ProfileSection from './sections/ProfileSection';
import MyPostList from './sections/MyPostList';
import BookmarkList from './sections/BookmarkList';
import FollowSection from './sections/FollowSection';
import ActivityStats from './sidebar/ActivityStats';
import LearningProgress from './sidebar/LearningProgress';
import LearningStreak from './sidebar/LearningStreak';
import QuickMenu from './sidebar/QuickMenu';
import ChatTab from './tabs/ChatTab';
import LicenseTab from './tabs/LicenseTab';
import SettingsTab from './tabs/SettingsTab';

const TABS = [
  { key: 'mypage',   label: '마이페이지' },
  { key: 'chat',     label: '채팅' },
  { key: 'license',  label: '자격증' },
  { key: 'settings', label: '설정' },
];

const MyPageComponent = ({ activeTab, onTabChange, user, activity, learning }) => {
  return (
    <div>
      <h1>마이페이지</h1>
      <div>
        {TABS.map(tab => (
          <button key={tab.key} onClick={() => onTabChange(tab.key)}>
            {tab.label}
          </button>
        ))}
      </div>

      {activeTab === 'mypage' && (
        <div>
          <div>
            <ProfileSection user={user} />
            <MyPostList />
            <BookmarkList />
            <FollowSection />
          </div>
          <div>
            <ActivityStats activity={activity} />
            <LearningProgress learning={learning} />
            <LearningStreak />
            <QuickMenu />
          </div>
        </div>
      )}
      {activeTab === 'chat'     && <ChatTab />}
      {activeTab === 'license'  && <LicenseTab />}
      {activeTab === 'settings' && <SettingsTab />}
    </div>
  );
};

export default MyPageComponent;
