import React from 'react';
import { Link } from 'react-router-dom';

const LoginComponent = ({ onSubmit, onChange, form }) => {
  return (
    <div>
      <h1>로그인</h1>
      <form onSubmit={onSubmit}>
        <div>
          <label>아이디</label>
          <input type="text" name="userId" value={form.userId} onChange={onChange} placeholder="아이디를 입력하세요" />
        </div>
        <div>
          <label>비밀번호</label>
          <input type="password" name="password" value={form.password} onChange={onChange} placeholder="비밀번호를 입력하세요" />
        </div>
        <button type="submit">로그인</button>
      </form>
      <p>계정이 없으신가요? <Link to="/eum/join">회원가입</Link></p>
    </div>
  );
};

export default LoginComponent;
